import { getAlphaColor, getSolidColor } from "./colorAlgorithm.js";
import { generate } from "@ant-design/colors";

//#region src/theme/themes/default/colors.ts
const generateColorPalettes = (baseColor) => {
	const colors = generate(baseColor);
	return {
		1: colors[0],
		2: colors[1],
		3: colors[2],
		4: colors[3],
		5: colors[4],
		6: colors[5],
		7: colors[6],
		8: colors[4],
		9: colors[5],
		10: colors[6]
	};
};
const generateNeutralColorPalettes = (bgBaseColor, textBaseColor, shadowColor) => {
	const colorBgBase = bgBaseColor || "#fff";
	const colorTextBase = textBaseColor || "#000";
	return {
		colorBgBase,
		colorTextBase,
		colorShadow: shadowColor || "#000",
		colorText: getAlphaColor(colorTextBase, .88),
		colorTextSecondary: getAlphaColor(colorTextBase, .65),
		colorTextTertiary: getAlphaColor(colorTextBase, .45),
		colorTextQuaternary: getAlphaColor(colorTextBase, .25),
		colorFill: getAlphaColor(colorTextBase, .15),
		colorFillSecondary: getAlphaColor(colorTextBase, .06),
		colorFillTertiary: getAlphaColor(colorTextBase, .04),
		colorFillQuaternary: getAlphaColor(colorTextBase, .02),
		colorBgSolid: getAlphaColor(colorTextBase, 1),
		colorBgSolidHover: getAlphaColor(colorTextBase, .75),
		colorBgSolidActive: getAlphaColor(colorTextBase, .95),
		colorBgLayout: getSolidColor(colorBgBase, 4),
		colorBgContainer: getSolidColor(colorBgBase, 0),
		colorBgElevated: getSolidColor(colorBgBase, 0),
		colorBgSpotlight: getAlphaColor(colorTextBase, .85),
		colorBgBlur: "transparent",
		colorBorder: getSolidColor(colorBgBase, 15),
		colorBorderDisabled: getSolidColor(colorBgBase, 15),
		colorBorderSecondary: getSolidColor(colorBgBase, 6)
	};
};

//#endregion
export { generateColorPalettes, generateNeutralColorPalettes };